private fun discoverPdfLinks(pageUrl: String): List<Pair<String, String>> {
    val result = mutableListOf<Pair<String, String>>()

    // 检测是否为SPA页面
    val isSpaPage = detectSpaPage(pageUrl)

    try {
        val doc = org.jsoup.Jsoup.connect(pageUrl)
            .userAgent("Mozilla/5.0")
            .timeout(15000)
            .get()

        // 原有逻辑...

        // 如果是SPA且没有找到PDF，直接返回空列表让WebView处理
        if (isSpaPage && result.isEmpty()) {
            return emptyList()
        }
    } catch (e: Exception) {
        Log.d(TAG, "PdfDownloader: Jsoup failed for $pageUrl: ${e.message}")
    }
    return result.distinctBy { it.first }
}

private fun detectSpaPage(url: String): Boolean {
    // 检测hash路由
    if (url.contains("#") || url.contains("/#!/")) {
        return true
    }
    // 检测已知的SPA域名
    val spaDomains = listOf("example-spa.com", "court-spa.gov.cn")
    return spaDomains.any { url.contains(it) }
}
```

