fun autoProcessPendingWebviewDocuments() {
    viewModelScope.launch(Dispatchers.IO) {
        // 查找所有待处理的WebView文档
        val pendingDocs = db.documentDao().getPendingWebviewDocs()

        for (doc in pendingDocs) {
            // 延迟触发，避免同时启动多个WebView
            launch {
                delay((doc.id % 5) * 1000L) // 分散启动时间

                // 检查是否已经在处理中
                val isProcessing = db.documentDao().isProcessing(doc.sourceUrl)
                if (!isProcessing) {
                    // 标记为处理中
                    db.documentDao().update(doc.copy(parseStatus = 5)) // 5 = processing

                    // 触发WebViewActivity
                    withContext(Dispatchers.Main) {
                        val intent = Intent(getApplication(), WebViewActivity::class.java).apply {
                            putExtra("url", doc.sourceUrl)
                            putExtra("smsId", doc.smsId)
                            putExtra("docId", doc.id)
                        }
                        // 使用FLAG_ACTIVITY_NEW_TASK确保能启动
                        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                        getApplication().startActivity(intent)
                    }
                }
            }
        }
    }
}
